'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import type { AppData } from '@/lib/api';

export default function AdminDashboard() {
  const [data, setData] = useState<AppData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const router = useRouter();

  useEffect(() => {
    // Check authentication
    const token = localStorage.getItem('adminToken');
    if (!token) {
      router.push('/admin/login');
      return;
    }

    setIsAuthenticated(true);
    fetchData();
  }, [router]);

  const fetchData = async () => {
    try {
      const res = await fetch('/api/data');
      const jsonData = await res.json();
      setData(jsonData);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('adminToken');
    localStorage.removeItem('adminUser');
    router.push('/admin/login');
  };

  if (!isAuthenticated || loading) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <div className="text-xl font-semibold">Loading...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      {/* Header */}
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 py-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-bold text-gray-900">Admin Dashboard</h1>
            <div className="flex items-center gap-4">
              <Link
                href="/"
                className="px-4 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition"
              >
                View Site
              </Link>
              <button
                onClick={handleLogout}
                className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-sm font-medium text-gray-500 mb-2">Total Drafts</h3>
            <p className="text-3xl font-bold text-gray-900">{data?.drafts?.length || 0}</p>
          </div>

          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-sm font-medium text-gray-500 mb-2">Categories</h3>
            <p className="text-3xl font-bold text-gray-900">{data?.categories?.length || 0}</p>
          </div>

          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-sm font-medium text-gray-500 mb-2">Menu Items</h3>
            <p className="text-3xl font-bold text-gray-900">{data?.menu?.length || 0}</p>
          </div>
        </div>

        {/* Management Sections */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Drafts Management */}
          <div className="bg-white rounded-lg shadow">
            <div className="p-6 border-b">
              <div className="flex items-center justify-between">
                <h2 className="text-xl font-semibold text-gray-900">Drafts</h2>
                <Link
                  href="/admin/drafts"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition text-sm"
                >
                  Manage Drafts
                </Link>
              </div>
            </div>
            <div className="p-6">
              <div className="space-y-3">
                {data?.drafts?.slice(0, 5).map((draft) => (
                  <div key={draft.href} className="flex items-center justify-between py-2 border-b">
                    <div>
                      <p className="font-medium text-gray-900">{draft.name}</p>
                      <p className="text-sm text-gray-500">₹{draft.price?.amount}</p>
                    </div>
                  </div>
                ))}
              </div>
              {(data?.drafts?.length || 0) > 5 && (
                <p className="text-sm text-gray-500 mt-4">
                  And {(data?.drafts?.length || 0) - 5} more...
                </p>
              )}
            </div>
          </div>

          {/* Categories Management */}
          <div className="bg-white rounded-lg shadow">
            <div className="p-6 border-b">
              <div className="flex items-center justify-between">
                <h2 className="text-xl font-semibold text-gray-900">Categories</h2>
                <Link
                  href="/admin/categories"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition text-sm"
                >
                  Manage Categories
                </Link>
              </div>
            </div>
            <div className="p-6">
              <div className="space-y-3">
                {data?.categories?.map((category) => (
                  <div key={category.href} className="flex items-center justify-between py-2 border-b">
                    <p className="font-medium text-gray-900">{category.name}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Menu Management */}
          <div className="bg-white rounded-lg shadow lg:col-span-2">
            <div className="p-6 border-b">
              <div className="flex items-center justify-between">
                <h2 className="text-xl font-semibold text-gray-900">Navigation Menu</h2>
                <Link
                  href="/admin/menu"
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition text-sm"
                >
                  Manage Menu
                </Link>
              </div>
            </div>
            <div className="p-6">
              <div className="space-y-3">
                {data?.menu?.map((menuItem) => (
                  <div key={menuItem.name} className="py-2 border-b">
                    <p className="font-medium text-gray-900">{menuItem.name}</p>
                    {menuItem.items && (
                      <p className="text-sm text-gray-500 mt-1">
                        {menuItem.items.length} sub-items
                      </p>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
